package com.i2i.voltwise.telemetry;
import com.fasterxml.jackson.databind.ObjectMapper;import com.i2i.voltwise.audit.*;import com.i2i.voltwise.home.*;import com.i2i.voltwise.notification.NotificationService;import com.i2i.voltwise.state.*;import jakarta.transaction.Transactional;import org.springframework.kafka.annotation.KafkaListener;import org.springframework.stereotype.Service;import java.time.*;
@Service public class TelemetryProcessor { private final ObjectMapper json;private final LiveStateService live;private final HomeRepository homes;private final SnapshotRepository snapshots;private final EventRepository events;private final NotificationService notifications;public TelemetryProcessor(ObjectMapper j,LiveStateService l,HomeRepository h,SnapshotRepository s,EventRepository e,NotificationService n){json=j;live=l;homes=h;snapshots=s;events=e;notifications=n;} @KafkaListener(topics="${voltwise.kafka.telemetry-topic}") public void consume(String payload){try{process(json.readValue(payload,TelemetryEvent.class));}catch(Exception ignored){}} @Transactional void process(TelemetryEvent t){var state=live.get(t.homeId());if(state==null)return;var device=state.appliances.get(t.applianceId());if(device==null)return;long previous=state.updatedAt==0?t.capturedAt().minusSeconds(3).toEpochMilli():state.updatedAt;double hours=Math.max(1,Duration.between(Instant.ofEpochMilli(previous),t.capturedAt()).toMillis()/1000d)/3600d;double delta=Math.max(0,t.watts())/1000d*hours;double tariff=state.baseTariff*(state.penalty?state.penaltyMultiplier:1);device.watts=t.watts();device.breachCount=t.watts()>device.safeLimit?device.breachCount+1:0;boolean newAnomaly=!device.anomalous&&device.breachCount>=3;device.anomalous=device.breachCount>=3;state.energyKwh+=delta;state.cost+=delta*tariff;double pct=state.cost/state.budgetLimit*100;boolean warn=!state.warningSent&&pct>=80;boolean breach=!state.breachSent&&pct>=100;if(warn)state.warningSent=true;if(breach){state.breachSent=true;state.penalty=true;}state.updatedAt=t.capturedAt().toEpochMilli();live.put(state);var home=homes.findById(t.homeId()).orElseThrow();snapshots.save(new ConsumptionSnapshot(home,state.energyKwh,state.cost));if(warn){events.save(new AuditEvent(home,"QUOTA_80","Bütçenin %80'i aşıldı"));notifications.notify(home,state,"Bütçenin yüzde 80'i aşıldı");}if(breach){events.save(new AuditEvent(home,"QUOTA_100_PENALTY","Bütçe aşıldı; ceza tarifesi etkin"));notifications.notify(home,state,"Bütçe aşıldı ve ceza tarifesi etkinleştirildi");}if(newAnomaly){events.save(new AuditEvent(home,"APPLIANCE_ANOMALY",device.name+" üç ardışık çevrimde limiti aştı"));notifications.notify(home,state,device.name+" cihazında ardışık güç limiti ihlali");}} }
